import React, { useState, useEffect } from "react";
import axios from "axios";

function Dashboard() {
    const [file, setFile] = useState(null);
    const [resumes, setResumes] = useState([]);
    const token = localStorage.getItem("token");

    // ✅ LOAD RESUMES AUTOMATICALLY
    useEffect(() => {
        fetchResumes();
    }, []);

    const fetchResumes = async () => {
        try {
            const res = await axios.get("http://localhost:8080/resumes", {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            });
            setResumes(res.data);
        } catch (err) {
            console.error("Error loading resumes", err);
        }
    };

    // ✅ UPLOAD
    const handleUpload = async () => {
        if (!file) {
            alert("Please select a file");
            return;
        }

        const formData = new FormData();
        formData.append("file", file);
        formData.append("name", "Test User");
        formData.append("email", "test@gmail.com");
        formData.append("skills", "java spring boot");
        formData.append("experience", 2);

        try {
            await axios.post(
                "http://localhost:8080/resumes/upload",
                formData,
                {
                    headers: {
                        Authorization: `Bearer ${token}`,
                        "Content-Type": "multipart/form-data"
                    }
                }
            );

            alert("Uploaded!");
            fetchResumes(); // 🔥 reload list
        } catch (err) {
            console.error(err);
            alert("Upload failed");
        }
    };

    // ✅ DELETE
    const deleteResume = async (id) => {
        try {
            await axios.delete(`http://localhost:8080/resumes/${id}`, {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            });

            fetchResumes(); // refresh
        } catch (err) {
            console.error(err);
            alert("Delete failed");
        }
    };

    return (
        <div style={{ padding: 30, fontFamily: "Arial" }}>
            <h2>📊 Dashboard</h2>

            <button
                onClick={() => {
                    localStorage.removeItem("token");
                    window.location.href = "/login";
                }}
            >
                Logout
            </button>
            <button onClick={getResumes}>View My Resumes</button>


            <hr />

            {/* ✅ UPLOAD SECTION */}
            <h3>Upload Resume</h3>

            <input type="file" onChange={(e) => setFile(e.target.files[0])} />
            <br /><br />

            <button onClick={handleUpload}>Upload</button>

            <hr />

            {/* ✅ RESUME LIST */}
            <h3>Your Resumes</h3>

            {resumes.length === 0 ? (
                <p>No resumes found</p>
            ) : (
                <table border="1" cellPadding="10" style={{ width: "100%" }}>
                    <thead>
                    <tr>
                        <th>Name</th>
                        <th>Email</th>
                        <th>Skills</th>
                        <th>Experience</th>
                        <th>Actions</th>
                    </tr>
                    </thead>

                    <tbody>
                    {resumes.map((r) => (
                        <tr key={r.id}>
                            <td>{r.name}</td>
                            <td>{r.email}</td>
                            <td>{r.skills}</td>
                            <td>{r.experience} yrs</td>

                            <td>
                                <button onClick={() => deleteResume(r.id)}>
                                    Delete
                                </button>
                            </td>
                        </tr>
                    ))}
                    </tbody>
                </table>
            )}
        </div>
    );
}

export default Dashboard;
